import{_ as s,o as e,c as i,ae as t}from"./chunks/framework.Czhw_PXq.js";const k=JSON.parse('{"title":"Call API","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/call.md","filePath":"zh/guide/call.md","lastUpdated":1776639249000}'),l={name:"zh/guide/call.md"};function n(p,a,r,o,h,d){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="call-api" tabindex="-1">Call API <a class="header-anchor" href="#call-api" aria-label="Permalink to &quot;Call API&quot;">​</a></h1><p>EasyYapi 支持在 IDEA 中直接发起 API 请求，方便快速测试和调试。</p><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h2><ol><li>打开项目中包含 API 的文件</li><li>右键文件内容选择 <code>Call</code></li><li>在弹出的面板中配置请求参数</li><li>点击发送按钮发起请求</li></ol><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><h3 id="请求前回调" tabindex="-1">请求前回调 <a class="header-anchor" href="#请求前回调" aria-label="Permalink to &quot;请求前回调&quot;">​</a></h3><p>使用 <code>http.call.before</code> 在发送请求前执行自定义逻辑：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">http.call.before</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&#39;&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">it.header(&quot;Authorization&quot;, &quot;Bearer &quot; + localStorage.get(&quot;token&quot;))</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&#39;&#39;</span></span></code></pre></div><h3 id="请求后回调" tabindex="-1">请求后回调 <a class="header-anchor" href="#请求后回调" aria-label="Permalink to &quot;请求后回调&quot;">​</a></h3><p>使用 <code>http.call.after</code> 在收到响应后执行自定义逻辑：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">http.call.after</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&#39;&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">if (it.response().code() == 200) {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    def body = it.response().body()</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    localStorage.set(&quot;token&quot;, body.token)</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&#39;&#39;</span></span></code></pre></div><p>详见 <a href="/zh/settings/rules/http_call_before">http.call.before</a> 和 <a href="/zh/settings/rules/http_call_after">http.call.after</a>。</p><h2 id="grpc-调用" tabindex="-1">gRPC 调用 <a class="header-anchor" href="#grpc-调用" aria-label="Permalink to &quot;gRPC 调用&quot;">​</a></h2><p>EasyYapi 还支持直接从 IDE 调用 gRPC 方法。此功能默认禁用，需要在配置中启用：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">grpc.call.enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true</span></span></code></pre></div><p>启用 gRPC 调用后，插件需要 gRPC 运行时 JAR 才能调用方法。可以通过以下方式配置运行时依赖：</p><ul><li><strong>IDE 设置</strong>：在 <kbd>Settings</kbd> &gt; <kbd>Other Settings</kbd> &gt; <kbd>EasyApi</kbd> &gt; gRPC Runtime 中使用 <strong>Auto Detect</strong> 按钮自动检测并解析依赖。</li><li><strong>配置文件</strong>：使用 <code>grpc.artifact.configs</code>、<code>grpc.additional.jars</code> 和 <code>grpc.repositories</code> 属性。</li></ul><p>详见 <a href="/zh/framework/grpc">gRPC 框架支持</a>。</p><h2 id="api-dashboard" tabindex="-1">API Dashboard <a class="header-anchor" href="#api-dashboard" aria-label="Permalink to &quot;API Dashboard&quot;">​</a></h2><p>EasyYapi 提供了 API Dashboard 工具窗口，方便快速访问 API 测试和管理。可以从 IDEA 底部工具窗口栏打开 Dashboard。</p><p>API Dashboard 允许你：</p><ul><li>浏览当前项目中检测到的所有 API</li><li>快速调用任何 API，自动填充参数</li><li>以结构化格式查看响应数据</li></ul>`,22)])])}const g=s(l,[["render",n]]);export{k as __pageData,g as default};
